mapper.select:
SELECT o.order_id, o.order_no, o.user_id, o.total_amount, o.actual_amount, 
       o.payment_method, o.payment_status, o.order_status, o.create_time, 
       o.pay_time, o.contact_name, o.contact_phone, o.remark,
       u.username
FROM orders o
LEFT JOIN users u ON o.user_id = u.user_id


        AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')


        AND u.username LIKE CONCAT('%', #{username}, '%')


        AND o.order_status = #{orderStatus}


        AND o.create_time >= #{startDate}


        AND o.create_time <= #{endDate}


ORDER BY o.create_time DESC
LIMIT #{offset}, #{size}

SELECT COUNT(*) 
FROM orders o
LEFT JOIN users u ON o.user_id = u.user_id


        AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')


        AND u.username LIKE CONCAT('%', #{username}, '%')


        AND o.order_status = #{orderStatus}


        AND o.create_time >= #{startDate}


        AND o.create_time <= #{endDate}
